parameters.jsCode:
const aiResponse = $json.choices[0].message.content;
const cleaned = aiResponse.replace(/^```(json)?\s*/i, '').replace(/\s*```$/, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); }
catch (e) { return [{ json: { success: false, error: 'Не удалось распарсить JSON', raw: aiResponse } }]; }

const original = $('Webhook — приём заявки').item.json.body;
return [{
  json: {
    success: true,
    data: parsed,
    validation: {
      amount_unchanged: String(parsed.amount).trim() === String(original.amount).trim(),
      email_unchanged: parsed.email === original.email,
      contact_unchanged: parsed.contact === original.contact
    }
  }
}];

